using MassTransit;
using Microservice.Basket.Api.Features.Baskets;
using Microservice.Bus.Events;

namespace Microservice.Basket.Api.Consumer
{
    public class OrderCreatedEventConsumer : IConsumer<OrderCreatedEvent>
    {
        private readonly BasketService _basketService;
        private readonly ILogger<OrderCreatedEventConsumer> _logger;

        public OrderCreatedEventConsumer\(
            BasketService basketService,
            ILogger<OrderCreatedEventConsumer> logger\)
        {
            _basketService = basketService;
            _logger = logger;
        }

        public async Task Consume\(ConsumeContext<OrderCreatedEvent> context\)
        {
            var message = context.Message;

            _logger.LogInformation\(
                "OrderCreatedEvent received. OrderId: {OrderId}, UserId: {UserId}",
                message.OrderId,
                message.UserId\);

            try
            {
                // TODO: Burada basket'i temizle veya işle
                // Örnek: Kullanıcının sepetini sil
                // await _basketService.DeleteBasketAsync\(message.UserId.ToString\(\)\);

                _logger.LogInformation\(
                    "Basket processed for OrderId: {OrderId}",
                    message.OrderId\);
            }
            catch \(Exception ex\)
            {
                _logger.LogError\(ex,
                    "Error processing basket for OrderId: {OrderId}",
                    message.OrderId\);
                throw;
            }
        }
    }
}
EOF)
